import { describe, expect, it } from 'vitest';

import {
  AcousticSourceCountingMaster,
  adist,
  admitSourceCount,
  allTight,
  intraTol,
  mergedOne,
  minMembers,
  overSplit,
  repOf,
  repsOf,
  sepThreshold,
  supported,
  tightness,
  twoClusters,
  wellSeparated,
} from '../src/acoustic-source-counting';

describe('adist (mirrors adist_self / adist_comm)', () => {
  it('is zero at a point with itself', () => {
    for (const a of [0, 10, 40]) {
      expect(adist(a, a)).toBe(0);
    }
  });

  it('is the absolute difference and symmetric', () => {
    expect(adist(10, 40)).toBe(30);
    expect(adist(40, 10)).toBe(30);
    expect(adist(10, 12)).toBe(2);
  });
});

describe('repOf', () => {
  it('takes the head, and 0 for the empty cluster', () => {
    expect(repOf([10, 11, 12])).toBe(10);
    expect(repOf([40])).toBe(40);
    expect(repOf([])).toBe(0);
  });
});

describe('tightness gate (mirrors clusterTightB / allTightB)', () => {
  it('a single-source cluster is tight (spread <= intraTol)', () => {
    expect(tightness(intraTol, [10, 11, 12])).toBe(true);
    expect(tightness(intraTol, [40, 41, 42])).toBe(true);
  });

  it('a merged two-source cluster is NOT tight (spread blows past intraTol)', () => {
    // head 10, member 42 => adist 32 > 5
    expect(tightness(intraTol, [10, 11, 12, 40, 41, 42])).toBe(false);
  });

  it('allTight folds over every cluster', () => {
    expect(allTight(intraTol, twoClusters)).toBe(true);
    expect(allTight(intraTol, mergedOne)).toBe(false);
    expect(allTight(intraTol, overSplit)).toBe(true);
  });
});

describe('separation gate (mirrors wellSeparatedB)', () => {
  it('the two honest clusters are well separated (reps 10 vs 40, gap 30 > 10)', () => {
    expect(wellSeparated(sepThreshold, twoClusters)).toBe(true);
    expect(repsOf(twoClusters)).toEqual([10, 40]);
  });

  it('the over-split is NOT well separated (reps 10 and 12, gap 2 <= 10)', () => {
    expect(wellSeparated(sepThreshold, overSplit)).toBe(false);
    expect(repsOf(overSplit)).toEqual([10, 12, 40]);
  });
});

describe('support gate (mirrors allSupportedB)', () => {
  it('every honest cluster has support (lengths 3,3 >= 1)', () => {
    expect(supported(minMembers, twoClusters)).toBe(true);
  });

  it('every over-split fragment has support too (lengths 2,1,3 >= 1)', () => {
    // the over-split is refuted by separation, NOT support
    expect(supported(minMembers, overSplit)).toBe(true);
  });

  it('rejects a fragment below minMembers', () => {
    expect(supported(2, overSplit)).toBe(false); // [12] has length 1 < 2
  });
});

describe('promotion check: admitSourceCount', () => {
  const opts = { intraTol, sepThreshold, minMembers };

  it('admits the honest 2-source grouping with count 2', () => {
    const a = admitSourceCount(twoClusters, opts);
    expect(a.outcome).toBe('claim_admitted');
    expect(a.count).toBe(2);
    expect(a.tight).toBe(true);
    expect(a.separated).toBe(true);
    expect(a.supported).toBe(true);
    expect(a.limitation).toBe('none');
  });

  it('withholds the over-merge (under-count) on the tightness gate', () => {
    const a = admitSourceCount(mergedOne, opts);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('over_merge_undercount');
    expect(a.count).toBe(1);
    expect(a.tight).toBe(false);
  });

  it('withholds the over-split (over-count) on the separation gate, not support', () => {
    const a = admitSourceCount(overSplit, opts);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('over_split_overcount');
    expect(a.count).toBe(3);
    expect(a.tight).toBe(true);
    expect(a.separated).toBe(false);
    expect(a.supported).toBe(true); // refuted on separation, not support
  });

  it('withholds an unsupported fragment when minMembers is raised', () => {
    const a = admitSourceCount(overSplit, { ...opts, minMembers: 2 });
    // overSplit fails separation first; raise sep to isolate support? reps gap
    // 2 still fails separation. Use a tight, separated but tiny clustering.
    expect(a.outcome).toBe('claim_withheld');
    const b = admitSourceCount([[10], [40]], {
      intraTol,
      sepThreshold,
      minMembers: 2,
    });
    expect(b.outcome).toBe('claim_withheld');
    expect(b.limitation).toBe('unsupported_fragment');
  });

  it('reports the empty clustering as observation_only', () => {
    const a = admitSourceCount([], opts);
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('empty_clustering');
    expect(a.count).toBe(0);
  });
});

describe('same window, count fixed by separation (mirrors same_window_count_fixed_by_separation)', () => {
  const opts = { intraTol, sepThreshold, minMembers };
  it('the same window admits count 2 but rejects the over-merged count 1', () => {
    expect(admitSourceCount(twoClusters, opts).outcome).toBe('claim_admitted');
    expect(admitSourceCount(mergedOne, opts).outcome).toBe('claim_withheld');
  });
});

describe('AcousticSourceCountingMaster (mirrors source_counting_master)', () => {
  it('every boundary witness holds', () => {
    expect(AcousticSourceCountingMaster.twoClustersTight).toBe(true);
    expect(AcousticSourceCountingMaster.mergedOneNotTight).toBe(true);
    expect(AcousticSourceCountingMaster.twoClustersSeparated).toBe(true);
    expect(AcousticSourceCountingMaster.overSplitNotSeparated).toBe(true);
    expect(AcousticSourceCountingMaster.twoClustersSupported).toBe(true);
    expect(AcousticSourceCountingMaster.overSplitSupported).toBe(true);
    expect(AcousticSourceCountingMaster.twoSourcesAdmitted).toBe(true);
    expect(AcousticSourceCountingMaster.twoSourcesCount).toBe(true);
    expect(AcousticSourceCountingMaster.overMergeRejected).toBe(true);
    expect(AcousticSourceCountingMaster.overSplitRejected).toBe(true);
  });
});
